package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenTempKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.VrbrwWrkwBv;
import lombok.extern.slf4j.Slf4j;

import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.RUW_BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.VRIJSTELLING_BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRE_BEREKENING_CONTEXT_VORIG_FISCAAL_JAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

@Slf4j
public class BerekenBelastbaarVrijwilligeBrandweer extends AbstractRekenCommand {

    private ConstantManager constantManager;

    public BerekenBelastbaarVrijwilligeBrandweer(ConstantManager constantManager, NlpGlobalService service) {
        this.constantManager = constantManager;
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        PersoonsFiscaliteit persoonsFiscaliteit = persoonsDataManager.getPersoonsFiscaliteitOpStartFiscaalJaar();
        VrbrwWrkwBv fiscaleWerkwijze = null;
        if (persoonsFiscaliteit != null) {
            fiscaleWerkwijze = persoonsFiscaliteit.getWerkwijzeVrijwilligeBrandweer();
        }
        Persoon persoonKwartaalSimpel = persoonsDataManager.getPersoonKwartaalSimpel();
        if (RekenTools.heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(persoonKwartaalSimpel)) {
            if (fiscaleWerkwijze != VrbrwWrkwBv.BAREMA_GFV && fiscaleWerkwijze != VrbrwWrkwBv.PERCENTAGE_GFV) {
                RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);

                Collection<LoonElement> loonElementen = RekenTools.filter(manager.getPersoonsElementen(), BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);

                Collection<LoonElement> prevLoonElementen = bepaalPrevLoonElementen(mainContext);

                Money ruwBelastbaarOther = persoonsDataManager.getRuwBelastbaarOtherVrijwilligeBrandweer();
                Money prevRuwBelastbaar = RekenTools.getSomProperty(RUW_BELASTBAAR_KEY, prevLoonElementen);
                Money ruwBelastbaar = RekenTools.getSomProperty(RUW_BELASTBAAR_KEY, loonElementen);
                Money ruwBelastbaarNu = ruwBelastbaar.subtract(prevRuwBelastbaar);
                Money ruwBelastbaarTotaal = ruwBelastbaarNu.add(ruwBelastbaarOther);

                Money grensVrijstelling = constantManager.getActualConstant(Konstanten.KST_GRENS_BV_VRIJW_BRW, rekenTijd).getMoney();
                grensVrijstelling = grensVrijstelling.add(persoonsDataManager.getBijsturingGrensVrijstellingVrijwilligeBrandweer());
                if (grensVrijstelling.signum() < 0) {
                    regulManager.addRegul(rekenTijd.eindDatum, null, Regulkode.FOUT_BIJSTURING_FISCALE_GRENS);
                }
                Money vrijstellingOther = persoonsDataManager.getVrijstellingBelastbaarOtherVrijwilligeBrandweer();
                Money vrijstellingTotaal = ruwBelastbaarTotaal.min(grensVrijstelling).max(Money.ZERO);
                Money vrijstelling = vrijstellingTotaal.subtract(vrijstellingOther);
                if (vrijstelling.signum() < 0) {
                    vrijstelling = Money.ZERO;
                }

                Money belastbaarNu = ruwBelastbaarNu.subtract(vrijstelling);
                if (belastbaarNu.signum() < 0) {
                    vrijstelling = vrijstelling.min(ruwBelastbaarNu).max(Money.ZERO);
                }

                Money totaalDiff = Money.ZERO;
                overnemenVorigFiscaalJaar(manager, prevLoonElementen);
                loonElementen = RekenTools.filter(manager.getPersoonsElementen(), BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);
                for (LoonElement element : loonElementen) {
                    Money belastbaar = element.getPropertyMoney(RekenBbKey.BELASTBAAR_KEY);
                    Money belastbaarRuw = element.getPropertyMoney(RekenBbKey.RUW_BELASTBAAR_KEY);
                    Money vrijstellingElement = element.getPropertyMoney(RekenBbKey.VRIJSTELLING_BELASTBAAR_KEY);
                    Money diff = belastbaarRuw.subtract(belastbaar).subtract(vrijstellingElement);
                    if (diff.signum() != 0) {
                        totaalDiff = totaalDiff.add(diff);
                        element.putProperty(RekenTempKey.TEMP_KEY, diff);
                    }
                }

                BedragVerdelerFactory.verdeelBedragVolgensBasisAdd(VRIJSTELLING_BELASTBAAR_KEY, vrijstelling, RekenTempKey.TEMP_KEY, totaalDiff, loonElementen);
                for (LoonElement element : loonElementen) {
                    Money belastbaarRuw = element.getPropertyMoney(RekenBbKey.RUW_BELASTBAAR_KEY);
                    Money vrijstellingElement = element.getPropertyMoney(RekenBbKey.VRIJSTELLING_BELASTBAAR_KEY);
                    element.putProperty(BELASTBAAR_KEY, belastbaarRuw.subtract(vrijstellingElement));
                }
                RekenTools.verwijderenVolgensVorigeBerekening(VRIJSTELLING_BELASTBAAR_KEY, manager, prevLoonElementen);

                log.trace("loonElementen VrBrw:{}", loonElementen);
            }
        }
        return CONTINUE_PROCESSING;
    }

    private Collection<LoonElement> bepaalPrevLoonElementen(RekenContext mainContext) {
        Collection<be.schaubroeck.lpb.rkm.rekenmotor.LoonElement> prevLoonElementen = be.schaubroeck.lpb.rkm.rekenmotor.LoonElement.createSortedSet();
        RekenContext preBerekeningContext = mainContext.getUnchecked(PRE_BEREKENING_CONTEXT_VORIG_FISCAAL_JAAR_KEY);
        if (preBerekeningContext != null && !preBerekeningContext.isEmpty()) {
            LoonElementManager prevManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
            prevLoonElementen = RekenTools.filter(prevManager.getPersoonsElementen(), BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);
        }
        return prevLoonElementen;
    }

    private void overnemenVorigFiscaalJaar(LoonElementManager manager, Collection<LoonElement> prevElementen) {
        RekenTools.overnemenVanVorigeBerekening(BELASTBAAR_KEY, manager, prevElementen);
        RekenTools.overnemenVanVorigeBerekening(VRIJSTELLING_BELASTBAAR_KEY, manager, prevElementen);
    }

}
